// Extract email data
const items = $input.all();
const result = [];

for (const item of items) {
  const email = item.json;

  result.push({
    json: {
      id: email.id,
      threadId: email.threadId,
      subject: email.payload?.headers?.find(h => h.name === 'Subject')?.value || '',
      from: email.payload?.headers?.find(h => h.name === 'From')?.value || '',
      to: email.payload?.headers?.find(h => h.name === 'To')?.value || '',
      date: email.payload?.headers?.find(h => h.name === 'Date')?.value || '',
      body: email.snippet || '',
      headers: Object.fromEntries(
        (email.payload?.headers || []).map(h => [h.name, h.value])
      )
    }
  });
}

return result;

// Detect language
const text = `${$json.subject}\n\n${$json.body}`;

let language = 'en';
if (/\b(olá|obrigad|preciso|ajuda|produto|acesso|dúvida|cartão|quero|meu|volta|dinheiro)\b/i.test(text)) {
  language = 'pt';
} else if (/\b(hola|gracias|necesito|producto|duda|tarjeta|crédito|devolución|quiero|mi)\b/i.test(text)) {
  language = 'es';
}

return {
  ...($json),
  language: language
};

